previewCss:
.darma-loader-loaders-css-31 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      min-width: 76px;
      min-height: 26px;
    }
    .darma-loader-loaders-css-31 i {
      display: block;
      width: 13px;
      height: 13px;
      border-radius: 50%;
      background: var(--loader-color, #8b5cf6);
      animation: darma-loader-loaders-css-31-dotPulse 0.7799999999999999s ease-in-out infinite;
    }
    .darma-loader-loaders-css-31 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loaders-css-31 i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-loaders-css-31 i:nth-child(3) { animation-delay: 0.24s; }
.darma-loader-loaders-css-31 i:nth-child(4) { animation-delay: 0.36s; }
    @keyframes darma-loader-loaders-css-31-dotPulse { 0%, 80%, 100% { opacity: .25; transform: scale(.7); } 40% { opacity: 1; transform: scale(1); } }

